const { v4: uuidv4 } = require('uuid');
return [{
  json: {
    correlationId: uuidv4(),
    startedAt: new Date().toISOString(),
    executionId: $execution.id,
    workflowName: 'WF-03-news-intelligence',
    rateLimitKey: 'wcic:rl:wf03:openai',
    deduplicationSetKey: 'wcic:dedup:news',
  }
}];

// ============================================================
// Normaliza artigos do NewsAPI para schema interno
// ============================================================
const source = $('Split by Source').item.json;
const apiResponse = $input.first().json;

const rawArticles = apiResponse.articles || [];
const normalized = [];

for (const a of rawArticles) {
  if (!a.url || !a.title || a.title === '[Removed]') continue;

  // Gera url_hash como SHA-256 hex da URL normalizada
  // n8n não tem crypto nativo, usamos base64 como aproximação para dedup
  // (hash real será calculado via execução SQL com md5 ou pelo índice UNIQUE)
  const urlNormalized = a.url.toLowerCase().split('?')[0].replace(/\/$/, '');
  const urlHash = Buffer.from(urlNormalized).toString('hex').substring(0, 64).padEnd(64, '0');

  normalized.push({
    url:          a.url,
    url_hash:     urlHash,
    source:       source.name,
    title:        a.title,
    description:  a.description || null,
    content:      a.content || null,
    author:       a.author || null,
    language:     source.language,
    published_at: a.publishedAt || null,
  });
}

return normalized.map(n => ({ json: n }));

// ============================================================
// Normaliza feed RSS para schema interno
// RSS retorna XML que o n8n converte automaticamente para JSON
// ============================================================
const source = $('Split by Source').item.json;
const rssData = $input.first().json;

// O n8n converte RSS/XML para JSON - estrutura varia por feed
const items = rssData.items || rssData.channel?.item || rssData.rss?.channel?.item || [];
const itemList = Array.isArray(items) ? items : [items];

const normalized = [];

for (const item of itemList) {
  const url   = item.link || item.guid || null;
  const title = item.title || null;
  if (!url || !title) continue;

  const urlNormalized = url.toLowerCase().split('?')[0].replace(/\/$/, '');
  const urlHash = Buffer.from(urlNormalized).toString('hex').substring(0, 64).padEnd(64, '0');

  // Limpa tags HTML da descrição RSS
  const rawDesc = item.description || item.summary || item['content:encoded'] || '';
  const description = rawDesc.replace(/<[^>]*>/g, '').substring(0, 1000) || null;

  normalized.push({
    url,
    url_hash:     urlHash,
    source:       source.name,
    title:        String(title).substring(0, 500),
    description,
    content:      null,
    author:       item.author || item['dc:creator'] || null,
    language:     source.language,
    published_at: item.pubDate || item.published || item['dc:date'] || null,
  });
}

return normalized.map(n => ({ json: n }));

// ============================================================
// Deduplicação: filtra artigos cujo url_hash já foi processado
// Usa o SET Redis wcic:dedup:news como bloom filter eficiente
// ============================================================
const dedupResult = $input.first().json;
const processedHashes = new Set(dedupResult.value || []);

// Coleta artigos de ambas as fontes normalizadas
let allArticles = [];
try { allArticles = [...allArticles, ...$('Normalize NewsAPI Articles').all().map(i => i.json)]; } catch(e) {}
try { allArticles = [...allArticles, ...$('Normalize RSS Articles').all().map(i => i.json)]; } catch(e) {}

const newArticles = allArticles.filter(a => a.url_hash && !processedHashes.has(a.url_hash));

// Remove duplicatas dentro do batch atual (mesmo url_hash)
const seen = new Set();
const dedupedBatch = newArticles.filter(a => {
  if (seen.has(a.url_hash)) return false;
  seen.add(a.url_hash);
  return true;
});

const initData = $('Init').first().json;
console.log(`[WF-03] Total: ${allArticles.length}, Novos: ${dedupedBatch.length}`);

return dedupedBatch.map(a => ({ json: { ...a, correlationId: initData.correlationId } }));

