INSERT INTO wcic.news (
  url, url_hash, source, title, description, content,
  author, language, published_at, processing_status
) VALUES ($1, $2, $3, $4, $5, $6, $7, $8, $9::timestamptz, 'pending')
ON CONFLICT (url_hash) DO NOTHING
RETURNING id::text, url_hash, title;

