  execution_id, workflow_name, status, started_at, finished_at,
  duration_ms, trigger_type, correlation_id, items_processed, output_summary
) VALUES (
  $1, 'WF-03-news-intelligence', 'success', $2::timestamptz, NOW(),
  EXTRACT(EPOCH FROM (NOW() - $2::timestamptz)) * 1000,
  'cron', $3::uuid, $4, $5::jsonb
);
